namespace RecipeShare.Services;

public class Recipe
{
    public int Id { get; set; }
    public string Title { get; set; } = string.Empty;
    public string Category { get; set; } = string.Empty;
    public List<string> Ingredients { get; set; } = new();
    public List<string> Steps { get; set; } = new();
    public double AverageRating { get; set; }
    public int RatingCount { get; set; }
}

public class RecipeService
{
    private readonly List<Recipe> _recipes = new()
    {
        new Recipe
        {
            Id = 1,
            Title = "Classic Margherita Pizza",
            Category = "Italian",
            Ingredients = new() { "Pizza dough", "San Marzano tomatoes", "Fresh mozzarella", "Fresh basil", "Olive oil", "Salt" },
            Steps = new() { "Preheat oven to 475°F (245°C).", "Roll out dough on a floured surface.", "Spread crushed tomatoes evenly.", "Tear mozzarella and distribute over sauce.", "Bake for 10-12 minutes until crust is golden.", "Top with fresh basil and a drizzle of olive oil." },
            AverageRating = 4.5,
            RatingCount = 12
        },
        new Recipe
        {
            Id = 2,
            Title = "Chicken Tikka Masala",
            Category = "Indian",
            Ingredients = new() { "Chicken breast", "Yogurt", "Garam masala", "Tomato sauce", "Heavy cream", "Onion", "Garlic", "Ginger" },
            Steps = new() { "Marinate chicken in yogurt and spices for 2 hours.", "Grill or pan-fry chicken until charred.", "Sauté onion, garlic, and ginger.", "Add tomato sauce and simmer 15 minutes.", "Stir in cream and cooked chicken.", "Serve over basmati rice." },
            AverageRating = 4.8,
            RatingCount = 24
        },
        new Recipe
        {
            Id = 3,
            Title = "Beef Tacos",
            Category = "Mexican",
            Ingredients = new() { "Ground beef", "Taco shells", "Lettuce", "Tomato", "Cheddar cheese", "Sour cream", "Taco seasoning" },
            Steps = new() { "Brown ground beef in a skillet.", "Add taco seasoning and water, simmer 5 minutes.", "Warm taco shells in oven.", "Assemble tacos with beef, lettuce, tomato, cheese.", "Top with sour cream and serve." },
            AverageRating = 4.2,
            RatingCount = 8
        },
        new Recipe
        {
            Id = 4,
            Title = "Pad Thai",
            Category = "Thai",
            Ingredients = new() { "Rice noodles", "Shrimp", "Eggs", "Bean sprouts", "Green onions", "Peanuts", "Tamarind paste", "Fish sauce", "Lime" },
            Steps = new() { "Soak rice noodles in warm water 30 minutes.", "Make sauce: mix tamarind paste, fish sauce, and sugar.", "Stir-fry shrimp until pink, set aside.", "Scramble eggs in the wok.", "Add noodles and sauce, toss until coated.", "Add shrimp, bean sprouts, and peanuts. Serve with lime." },
            AverageRating = 4.6,
            RatingCount = 15
        },
        new Recipe
        {
            Id = 5,
            Title = "Spaghetti Carbonara",
            Category = "Italian",
            Ingredients = new() { "Spaghetti", "Guanciale", "Eggs", "Pecorino Romano", "Black pepper" },
            Steps = new() { "Cook spaghetti in salted water until al dente.", "Crisp guanciale in a pan.", "Whisk eggs with grated Pecorino and pepper.", "Toss hot pasta with guanciale.", "Remove from heat, stir in egg mixture quickly.", "Serve immediately with extra cheese and pepper." },
            AverageRating = 4.7,
            RatingCount = 19
        },
        new Recipe
        {
            Id = 6,
            Title = "Chocolate Lava Cake",
            Category = "Desserts",
            Ingredients = new() { "Dark chocolate", "Butter", "Eggs", "Sugar", "Flour", "Vanilla extract" },
            Steps = new() { "Preheat oven to 425°F (220°C).", "Melt chocolate and butter together.", "Whisk eggs and sugar until thick.", "Fold chocolate mixture into eggs.", "Add flour and vanilla, mix gently.", "Pour into greased ramekins, bake 12-14 minutes." },
            AverageRating = 4.9,
            RatingCount = 30
        }
    };

    private readonly Dictionary<int, List<int>> _ratings = new();

    public List<string> GetCategories()
    {
        return _recipes.Select(r => r.Category).Distinct().OrderBy(c => c).ToList();
    }

    public List<Recipe> GetRecipesByCategory(string category)
    {
        return _recipes.Where(r => r.Category.Equals(category, StringComparison.OrdinalIgnoreCase)).ToList();
    }

    public List<Recipe> GetAllRecipes()
    {
        return _recipes.ToList();
    }

    public Recipe? GetRecipeById(int id)
    {
        return _recipes.FirstOrDefault(r => r.Id == id);
    }

    public void AddRating(int recipeId, int stars)
    {
        var recipe = _recipes.FirstOrDefault(r => r.Id == recipeId);
        if (recipe == null || stars < 1 || stars > 5) return;

        if (!_ratings.ContainsKey(recipeId))
            _ratings[recipeId] = new List<int>();

        _ratings[recipeId].Add(stars);

        var allRatings = _ratings[recipeId];
        recipe.AverageRating = Math.Round(allRatings.Average(), 1);
        recipe.RatingCount = recipe.RatingCount + 1;
    }

    public void AddRecipe(Recipe recipe)
    {
        recipe.Id = _recipes.Max(r => r.Id) + 1;
        _recipes.Add(recipe);
    }
}

