@page "/recipes"
@page "/recipes/{Category}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>Recipes - @(Category ?? "All")</PageTitle>

<h1>@(Category != null ? $"{Category} Recipes" : "All Recipes")</h1>

@if (Category == null)
{
    <p>Select a category to browse recipes, or view all below.</p>
}

<div class="row">
    @foreach (var recipe in GetRecipes())
    {
        <div class="col-md-6 mb-3">
            <div class="card h-100">
                <div class="card-body">
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text">
                        <span class="badge bg-secondary">@recipe.Category</span>
                        <span class="ms-2">⭐ @recipe.AverageRating (@recipe.RatingCount ratings)</span>
                    </p>
                    <a href="recipe/@recipe.Id" class="btn btn-outline-primary">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

@code {
    [Parameter]
    public string? Category { get; set; }

    private List<Recipe> GetRecipes()
    {
        if (!string.IsNullOrEmpty(Category))
            return RecipeService.GetRecipesByCategory(Category);
        return RecipeService.GetAllRecipes();
    }
}

@page "/recipe/{Id:int}"
@using RecipeShare.Services
@inject RecipeService RecipeService

<PageTitle>@(recipe?.Title ?? "Recipe") - RecipeShare</PageTitle>

@if (recipe == null)
{
    <p>Recipe not found.</p>
}
else
{
    <h1>@recipe.Title</h1>
    <span class="badge bg-secondary mb-3">@recipe.Category</span>

    <h3 class="mt-4">Ingredients</h3>
    <ul>
        @foreach (var ingredient in recipe.Ingredients)
        {
            <li>@ingredient</li>
        }
    </ul>

    <h3>Steps</h3>
    <ol>
        @foreach (var step in recipe.Steps)
        {
            <li class="mb-2">@step</li>
        }
    </ol>

    <h3>Rating</h3>
    <p>⭐ @recipe.AverageRating / 5 (@recipe.RatingCount ratings)</p>

    <StarRating RecipeId="recipe.Id" @rendermode="InteractiveServer" />
}

@code {
    [Parameter]
    public int Id { get; set; }

    private Recipe? recipe;

    protected override void OnInitialized()
    {
        recipe = RecipeService.GetRecipeById(Id);
    }
}

@using RecipeShare.Services
@inject RecipeService RecipeService
@rendermode InteractiveServer

<div class="my-3">
    <strong>Rate this recipe:</strong>
    <div class="d-inline-block ms-2" style="font-size: 1.5rem; cursor: pointer;">
        @for (int i = 1; i <= 5; i++)
        {
            var star = i;
            <span @onclick="() => Rate(star)"
                  @onmouseover="() => hoverRating = star"
                  @onmouseout="() => hoverRating = 0"
                  style="color: @(GetStarColor(star))">
                ★
            </span>
        }
    </div>

    @if (submitted)
    {
        <div class="alert alert-success mt-2" role="alert">
            Thanks! You rated this @selectedRating out of 5 stars.
        </div>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    private int hoverRating;
    private int selectedRating;
    private bool submitted;

    private string GetStarColor(int star)
    {
        if (hoverRating >= star) return "gold";
        if (selectedRating >= star) return "gold";
        return "#ccc";
    }

    private void Rate(int stars)
    {
        selectedRating = stars;
        submitted = true;
        RecipeService.AddRating(RecipeId, stars);
    }
}

@page "/submit"
@using RecipeShare.Services
@inject RecipeService RecipeService
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Submit a Recipe - RecipeShare</PageTitle>

<h1>Submit a Recipe</h1>
<p>Share your favorite recipe with the community!</p>

@if (successMessage != null)
{
    <div class="alert alert-success" role="alert">@successMessage</div>
}

<EditForm Model="model" OnValidSubmit="HandleSubmit" FormName="submitRecipe">
    <DataAnnotationsValidator />
    <ValidationSummary class="text-danger" />

    <div class="mb-3">
        <label for="title" class="form-label">Recipe Title</label>
        <InputText id="title" class="form-control" @bind-Value="model.Title" />
        <ValidationMessage For="() => model.Title" />
    </div>

    <div class="mb-3">
        <label for="category" class="form-label">Category</label>
        <InputSelect id="category" class="form-select" @bind-Value="model.Category">
            <option value="">-- Select a category --</option>
            <option value="Italian">Italian</option>
            <option value="Indian">Indian</option>
            <option value="Mexican">Mexican</option>
            <option value="Thai">Thai</option>
            <option value="Desserts">Desserts</option>
            <option value="Other">Other</option>
        </InputSelect>
        <ValidationMessage For="() => model.Category" />
    </div>

    <div class="mb-3">
        <label for="ingredients" class="form-label">Ingredients (one per line)</label>
        <InputTextArea id="ingredients" class="form-control" rows="5" @bind-Value="model.IngredientsText" />
        <ValidationMessage For="() => model.IngredientsText" />
    </div>

    <div class="mb-3">
        <label for="steps" class="form-label">Steps (one per line)</label>
        <InputTextArea id="steps" class="form-control" rows="5" @bind-Value="model.StepsText" />
        <ValidationMessage For="() => model.StepsText" />
    </div>

    <button type="submit" class="btn btn-primary">Submit Recipe</button>
</EditForm>

@code {
    private RecipeFormModel model = new();
    private string? successMessage;

    private void HandleSubmit()
    {
        var recipe = new Recipe
        {
            Title = model.Title,
            Category = model.Category,
            Ingredients = model.IngredientsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList(),
            Steps = model.StepsText
                .Split('\n', StringSplitOptions.RemoveEmptyEntries | StringSplitOptions.TrimEntries)
                .ToList()
        };

        RecipeService.AddRecipe(recipe);
        successMessage = $"'{recipe.Title}' has been submitted successfully!";
        model = new();
    }

    private class RecipeFormModel
    {
        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Title is required.")]
        public string Title { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Category is required.")]
        public string Category { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one ingredient.")]
        public string IngredientsText { get; set; } = string.Empty;

        [System.ComponentModel.DataAnnotations.Required(ErrorMessage = "Please add at least one step.")]
        public string StepsText { get; set; } = string.Empty;
    }
}

